from collections import Counter

class Solution(object):
    def minimumLength(self, s):
        freq = Counter(s)
        result = 0
        for cnt in freq.values():
            # Repeatedly remove pairs until <= 2 remain
            # If cnt is odd: left with 1
            # If cnt is even: left with 2
            if cnt % 2 == 1:
                result += 1
            else:
                result += 2
        return result
